const rawText = $input.first().json.data;

const lines = rawText.split('\n').filter(line => line.trim() !== '');
const result = {};

for (const line of lines) {
  const [key, value] = line.split(',');
  if (key && value) {
    result[key.trim()] = Number(value.trim());
  }
}

return [{
  json: {
    // Core
    totalShipments: result['Total Shipments'],
    delivered: result['Delivered'],
    notDelivered: result['Not Delivered'],

    // Segment Totals
    domesticShipment: result['Domestic Shipment'],
    internationalShipment: result['International Shipment'],
    domesticExpress: result['Domestic Express'],
    domesticRegular: result['Domestic Regular'],
    internationalExpress: result['International Express'],
    internationalRegular: result['International Regular'],

    // Delivered per Segment
    domesticExpressDelivered: result['Domestic Express Delivered'],
    domesticRegularDelivered: result['Domestic Regular Delivered'],
    internationalExpressDelivered: result['International Express Delivered'],
    internationalRegularDelivered: result['International Regular Delivered'],

    // Payments
    paymentCollected: result['Payment collected'],
    pendingCOD: result['Payment Remaining: COD'],
    pendingCard: result['Payment Remaining: Card Payment'],

    // Derived
    deliveryRate: ((result['Delivered'] / result['Total Shipments']) * 100).toFixed(1),
    totalPending: result['Payment Remaining: COD'] + result['Payment Remaining: Card Payment'],

    // Segment Delivery Rates
    domesticExpressRate: ((result['Domestic Express Delivered'] / result['Domestic Express']) * 100).toFixed(1),
    domesticRegularRate: ((result['Domestic Regular Delivered'] / result['Domestic Regular']) * 100).toFixed(1),
    internationalExpressRate: ((result['International Express Delivered'] / result['International Express']) * 100).toFixed(1),
    internationalRegularRate: ((result['International Regular Delivered'] / result['International Regular']) * 100).toFixed(1),

    // Not Delivered per Segment
    domesticExpressNotDelivered: result['Domestic Express'] - result['Domestic Express Delivered'],
    domesticRegularNotDelivered: result['Domestic Regular'] - result['Domestic Regular Delivered'],
    internationalExpressNotDelivered: result['International Express'] - result['International Express Delivered'],
    internationalRegularNotDelivered: result['International Regular'] - result['International Regular Delivered'],
  }
}];
